#!/usr/bin/env node
"use strict";

/**
 * metadata-validator.js — Validate Salesforce metadata files for deployment readiness
 *
 * Checks XML well-formedness, API version, merge conflict markers, duplicate elements,
 * standard object field detection, LWC bundle completeness, Apex controller imports,
 * and file classification.
 *
 * Usage:
 *   node scripts/metadata-validator.js [options]
 *
 * Options:
 *   --metadata-path <path>  Source metadata directory (default: force-app/main/default)
 *   --api-version <ver>     Expected API version (default: from sfdx-project.json or 62.0)
 *   --files <path,path,...>  Validate specific files (comma-separated)
 *   --git-diff [ref]        Validate files changed in git diff (default ref: HEAD)
 *   --json                  JSON output
 *   --summary               Summary counts only (no per-file detail)
 *   --help                  Show this help message
 *
 * Exit codes: 0 = valid, 1 = validation errors found
 */

const fs = require("fs");
const path = require("path");
const { execSync } = require("child_process");

const REPO_ROOT = path.join(__dirname, "..");

// ---------------------------------------------------------------------------
// Resolve API version from sfdx-project.json or fallback
// ---------------------------------------------------------------------------

function resolveApiVersion(cliOverride) {
  if (cliOverride) return cliOverride;
  try {
    const projFile = path.join(REPO_ROOT, "sfdx-project.json");
    const proj = JSON.parse(fs.readFileSync(projFile, "utf8"));
    if (proj.sourceApiVersion) return proj.sourceApiVersion;
  } catch {
    // No sfdx-project.json or parse error — use fallback
  }
  return "62.0";
}

// ---------------------------------------------------------------------------
// CLI argument parsing
// ---------------------------------------------------------------------------

function parseArgs() {
  const args = process.argv.slice(2);
  const opts = {
    metadataPath: null,
    apiVersion: null,
    files: null,
    gitDiff: false,
    gitDiffRef: null,
    json: false,
    summary: false
  };

  for (let i = 0; i < args.length; i++) {
    switch (args[i]) {
      case "--help":
        console.log(
          [
            "Usage: node scripts/metadata-validator.js [options]",
            "",
            "Options:",
            "  --metadata-path <path>  Source metadata directory (default: force-app/main/default)",
            "  --api-version <ver>     Expected API version (default: from sfdx-project.json or 62.0)",
            "  --files <path,path,...>  Validate specific files (comma-separated)",
            "  --git-diff [ref]        Validate files changed in git diff (default ref: HEAD)",
            "  --json                  JSON output",
            "  --summary               Summary counts only (no per-file detail)",
            "  --help                  Show this help message"
          ].join("\n")
        );
        process.exit(0);
        break;
      case "--metadata-path":
        opts.metadataPath = args[++i];
        break;
      case "--api-version":
        opts.apiVersion = args[++i];
        break;
      case "--files":
        opts.files = (args[++i] || "").split(",").filter(Boolean);
        break;
      case "--git-diff":
        opts.gitDiff = true;
        // Next arg is the optional ref (if it doesn't start with --)
        if (args[i + 1] && !args[i + 1].startsWith("--")) {
          opts.gitDiffRef = args[++i];
        }
        break;
      case "--json":
        opts.json = true;
        break;
      case "--summary":
        opts.summary = true;
        break;
      default:
        break;
    }
  }
  return opts;
}

const CLI_OPTS = parseArgs();
const EXPECTED_API_VERSION = resolveApiVersion(CLI_OPTS.apiVersion);
const METADATA_PATH = CLI_OPTS.metadataPath || "force-app/main/default";
const FORCE_APP = path.resolve(REPO_ROOT, METADATA_PATH, "..", "..");
const DEFAULT_PATH = path.resolve(REPO_ROOT, METADATA_PATH);

const STANDARD_OBJECTS = [
  "Account",
  "Contact",
  "Lead",
  "Opportunity",
  "Case",
  "Task",
  "Event",
  "Campaign",
  "Order",
  "Product2",
  "Pricebook2",
  "Contract",
  "Solution",
  "User"
];

const EXCLUDED_FILENAMES = new Set([".gitkeep", ".DS_Store", "Thumbs.db"]);

// Metadata type classification rules — order matters (first match wins)
const TYPE_RULES = [
  { pattern: /\/flows\/[^/]+\.flow-meta\.xml$/, type: "Flow" },
  {
    pattern: /\/objects\/[^/]+\/fields\/[^/]+\.field-meta\.xml$/,
    type: "CustomField"
  },
  {
    pattern: /\/permissionsets\/[^/]+\.permissionset-meta\.xml$/,
    type: "PermissionSet"
  },
  {
    pattern:
      /\/customNotificationTypes\/[^/]+\.customNotificationType-meta\.xml$/,
    type: "CustomNotificationType"
  },
  { pattern: /\/layouts\/[^/]+\.layout-meta\.xml$/, type: "Layout" },
  { pattern: /\/lwc\//, type: "LightningComponentBundle" },
  { pattern: /\/classes\/[^/]+\.cls$/, type: "ApexClass" },
  { pattern: /\/classes\/[^/]+\.cls-meta\.xml$/, type: "ApexClass" },
  { pattern: /\/triggers\/[^/]+\.trigger$/, type: "ApexTrigger" },
  { pattern: /\/triggers\/[^/]+\.trigger-meta\.xml$/, type: "ApexTrigger" },
  {
    pattern: /\/objects\/[^/]+\/[^/]+\.object-meta\.xml$/,
    type: "CustomObject"
  },
  {
    pattern: /\/flexipages\/[^/]+\.flexipage-meta\.xml$/,
    type: "FlexiPage"
  }
];

// ---------------------------------------------------------------------------
// File collection
// ---------------------------------------------------------------------------

function collectFilesRecursive(dir) {
  const results = [];
  if (!fs.existsSync(dir)) return results;
  const entries = fs.readdirSync(dir, { withFileTypes: true });
  for (const entry of entries) {
    const full = path.join(dir, entry.name);
    if (entry.isDirectory()) {
      results.push(...collectFilesRecursive(full));
    } else {
      results.push(full);
    }
  }
  return results;
}

function getFilesFromGitDiff(ref) {
  const diffRef = ref || "HEAD";
  const cmd = `git diff --name-only --diff-filter=ACMR ${diffRef}`;
  try {
    const output = execSync(cmd, { cwd: REPO_ROOT, encoding: "utf-8" });
    return output
      .split("\n")
      .map((f) => f.trim())
      .filter(Boolean)
      .map((f) => path.resolve(REPO_ROOT, f));
  } catch {
    // If git diff fails (e.g., no commits yet), return empty
    return [];
  }
}

function resolveFiles(opts) {
  if (opts.files) {
    return opts.files.map((f) => path.resolve(REPO_ROOT, f));
  }
  if (opts.gitDiff) {
    return getFilesFromGitDiff(opts.gitDiffRef);
  }
  return collectFilesRecursive(FORCE_APP);
}

// ---------------------------------------------------------------------------
// Classification
// ---------------------------------------------------------------------------

function normalizeToForward(p) {
  return p.replace(/\\/g, "/");
}

function isInForceApp(filePath) {
  const norm = normalizeToForward(filePath);
  const forceNorm = normalizeToForward(FORCE_APP);
  return norm.startsWith(forceNorm);
}

function classifyType(filePath) {
  const norm = normalizeToForward(filePath);
  for (const rule of TYPE_RULES) {
    if (rule.pattern.test(norm)) {
      return rule.type;
    }
  }
  // Fallback: derive from the directory name under the default path
  const defaultNorm = normalizeToForward(DEFAULT_PATH) + "/";
  if (norm.startsWith(defaultNorm)) {
    const relative = norm.slice(defaultNorm.length);
    const firstDir = relative.split("/")[0];
    if (firstDir) {
      // Convert directory name to PascalCase type name
      return firstDir.charAt(0).toUpperCase() + firstDir.slice(1);
    }
  }
  return "Unknown";
}

function isStandardObjectStub(filePath) {
  const norm = normalizeToForward(filePath);
  const match = norm.match(/\/objects\/([^/]+)\/\1\.object-meta\.xml$/);
  if (!match) return false;
  const objectName = match[1];
  if (!objectName.endsWith("__c") && STANDARD_OBJECTS.includes(objectName)) {
    const fieldsDir = path.join(path.dirname(filePath), "fields");
    if (!fs.existsSync(fieldsDir)) return true;
    const fields = fs.readdirSync(fieldsDir);
    return fields.length === 0;
  }
  return false;
}

// ---------------------------------------------------------------------------
// XML validation (regex-based, no external dependencies)
// ---------------------------------------------------------------------------

function validateXml(filePath, content) {
  const issues = { errors: [], warnings: [] };

  if (!content.trim()) {
    issues.errors.push("File is empty");
    return issues;
  }

  // Check balanced tags
  const openTags = [];
  const withoutComments = content.replace(/<!--[\s\S]*?-->/g, "");
  const withoutDecl = withoutComments.replace(/<\?[^?]*\?>/g, "");

  const tagRegex = /<\/?([a-zA-Z][a-zA-Z0-9_.:]*)[^>]*?\/?>/g;
  let match;
  while ((match = tagRegex.exec(withoutDecl)) !== null) {
    const fullTag = match[0];
    const tagName = match[1];

    if (fullTag.endsWith("/>")) {
      continue;
    }
    if (fullTag.startsWith("</")) {
      if (openTags.length === 0 || openTags[openTags.length - 1] !== tagName) {
        issues.errors.push(
          `Unbalanced closing tag </${tagName}> (expected </${openTags[openTags.length - 1] || "none"}>)`
        );
        return issues;
      }
      openTags.pop();
    } else {
      openTags.push(tagName);
    }
  }

  if (openTags.length > 0) {
    issues.errors.push(`Unclosed tag(s): ${openTags.join(", ")}`);
  }

  // Duplicate element detection
  const duplicateCheck = [
    "description",
    "label",
    "apiVersion",
    "status",
    "processType"
  ];
  for (const elem of duplicateCheck) {
    const elemRegex = new RegExp(`<${elem}[> ]`, "g");
    const matches = withoutComments.match(elemRegex);
    if (matches && matches.length > 1) {
      issues.errors.push(
        `Duplicate <${elem}> element (${matches.length} occurrences — possible merge conflict)`
      );
    }
  }

  // API version check
  const apiMatch = content.match(/<apiVersion>([\d.]+)<\/apiVersion>/);
  if (apiMatch) {
    const version = apiMatch[1];
    if (version !== EXPECTED_API_VERSION) {
      issues.warnings.push(
        `API version ${version}, expected ${EXPECTED_API_VERSION}`
      );
    }
  }

  // Check for merge conflict markers
  if (/^[<>=]{7}\s/m.test(content)) {
    issues.errors.push("File contains merge conflict markers");
  }

  return issues;
}

// ---------------------------------------------------------------------------
// Standard object field detection
// ---------------------------------------------------------------------------

function parseStandardObjectField(filePath) {
  const norm = normalizeToForward(filePath);
  const match = norm.match(
    /\/objects\/([^/]+)\/fields\/([^/]+)\.field-meta\.xml$/
  );
  if (!match) return null;
  const objectName = match[1];
  const fieldName = match[2];
  if (!objectName.endsWith("__c") && STANDARD_OBJECTS.includes(objectName)) {
    return `${objectName}.${fieldName}`;
  }
  return null;
}

// ---------------------------------------------------------------------------
// Main validation pipeline
// ---------------------------------------------------------------------------

function validate(files) {
  const result = {
    deployable: [],
    excluded: [],
    errors: [],
    warnings: [],
    summary: {
      total_files: files.length,
      deployable: 0,
      excluded: 0,
      errors: 0,
      warnings: 0,
      by_type: {},
      standard_object_fields: []
    }
  };

  for (const filePath of files) {
    const basename = path.basename(filePath);

    if (EXCLUDED_FILENAMES.has(basename)) {
      result.excluded.push({ path: filePath, reason: "Excluded filename" });
      continue;
    }

    if (!isInForceApp(filePath)) {
      result.excluded.push({ path: filePath, reason: "Not in force-app/" });
      continue;
    }

    if (isStandardObjectStub(filePath)) {
      result.excluded.push({
        path: filePath,
        reason: "Standard object stub without custom fields"
      });
      continue;
    }

    const metaType = classifyType(filePath);
    const entry = {
      path: filePath,
      type: metaType,
      valid: true,
      warnings: []
    };

    const isXml =
      filePath.endsWith(".xml") ||
      filePath.endsWith(".flow-meta.xml") ||
      filePath.endsWith(".object-meta.xml");

    if (isXml && fs.existsSync(filePath)) {
      let content;
      try {
        content = fs.readFileSync(filePath, "utf-8");
      } catch (e) {
        result.errors.push({
          path: filePath,
          type: metaType,
          error: `Cannot read file: ${e.message}`
        });
        continue;
      }

      const xmlResult = validateXml(filePath, content);

      for (const err of xmlResult.errors) {
        entry.valid = false;
        result.errors.push({ path: filePath, type: metaType, error: err });
      }

      for (const warn of xmlResult.warnings) {
        entry.warnings.push(warn);
        result.warnings.push({ path: filePath, warning: warn });
      }
    }

    const stdField = parseStandardObjectField(filePath);
    if (stdField) {
      result.summary.standard_object_fields.push(stdField);
    }

    result.deployable.push(entry);
    result.summary.by_type[metaType] =
      (result.summary.by_type[metaType] || 0) + 1;
  }

  // -------------------------------------------------------------------------
  // LWC bundle completeness + Apex controller import checks
  // -------------------------------------------------------------------------

  const lwcFiles = result.deployable.filter((e) => e.type === "LightningComponentBundle");
  if (lwcFiles.length > 0) {
    // Group by component bundle directory
    const bundles = {};
    for (const entry of lwcFiles) {
      const norm = normalizeToForward(entry.path);
      const lwcMatch = norm.match(/\/lwc\/([^/]+)\//);
      if (lwcMatch) {
        const name = lwcMatch[1];
        if (!bundles[name]) {
          bundles[name] = { dir: path.dirname(entry.path), files: [] };
          // Walk up to the component dir (may be nested)
          const parts = entry.path.replace(/\\/g, "/").split("/");
          const lwcIdx = parts.lastIndexOf("lwc");
          if (lwcIdx >= 0 && parts[lwcIdx + 1]) {
            bundles[name].dir = parts.slice(0, lwcIdx + 2).join(path.sep);
          }
        }
        bundles[name].files.push(path.basename(entry.path));
      }
    }

    for (const [name, bundle] of Object.entries(bundles)) {
      const dir = bundle.dir;
      const hasJs = fs.existsSync(path.join(dir, `${name}.js`));
      const hasHtml = fs.existsSync(path.join(dir, `${name}.html`));
      const hasMeta = fs.existsSync(path.join(dir, `${name}.js-meta.xml`));

      if (!hasMeta) {
        result.errors.push({
          path: dir,
          type: "LightningComponentBundle",
          error: `LWC bundle "${name}" missing ${name}.js-meta.xml`
        });
      }
      if (!hasJs) {
        result.errors.push({
          path: dir,
          type: "LightningComponentBundle",
          error: `LWC bundle "${name}" missing ${name}.js`
        });
      }
      if (!hasHtml) {
        // HTML is optional for headless LWC (service components)
        // Only warn, don't error
        result.warnings.push({
          path: dir,
          warning: `LWC bundle "${name}" has no ${name}.html (OK for service components)`
        });
      }

      // Check Apex controller imports in .js file
      const jsPath = path.join(dir, `${name}.js`);
      if (hasJs) {
        try {
          const jsContent = fs.readFileSync(jsPath, "utf-8");
          const apexImports = [...jsContent.matchAll(/from\s+['"]@salesforce\/apex\/([^.'"]+)/g)];
          for (const imp of apexImports) {
            const className = imp[1];
            const classFile = path.resolve(REPO_ROOT, METADATA_PATH, "classes", `${className}.cls`);
            if (!fs.existsSync(classFile)) {
              result.warnings.push({
                path: jsPath,
                warning: `Imports Apex class "${className}" but ${METADATA_PATH}/classes/${className}.cls not found locally`
              });
            }
          }
        } catch {
          // Can't read .js file — skip import check
        }
      }
    }
  }

  result.summary.deployable = result.deployable.length;
  result.summary.excluded = result.excluded.length;
  result.summary.errors = result.errors.length;
  result.summary.warnings = result.warnings.length;

  return result;
}

// ---------------------------------------------------------------------------
// Output formatting
// ---------------------------------------------------------------------------

function relativePath(p) {
  return path.relative(REPO_ROOT, p).replace(/\\/g, "/");
}

function formatHuman(result, summaryOnly) {
  const lines = [];
  const s = result.summary;

  const typeBreakdown = Object.entries(s.by_type)
    .sort((a, b) => b[1] - a[1])
    .map(([t, c]) => `${c} ${t}`)
    .join(", ");

  lines.push("Metadata Validation Report");
  lines.push("==========================");
  lines.push(
    `Deployable: ${s.deployable} files${typeBreakdown ? ` (${typeBreakdown})` : ""}`
  );
  lines.push(`Excluded: ${s.excluded} files`);
  lines.push(
    `Errors: ${s.errors}${s.errors > 0 ? " (fix before deploying)" : ""}`
  );
  lines.push(`Warnings: ${s.warnings}`);

  if (!summaryOnly) {
    if (result.errors.length > 0) {
      lines.push("");
      for (const err of result.errors) {
        lines.push(`  ERROR: ${relativePath(err.path)} — ${err.error}`);
      }
    }

    if (result.warnings.length > 0) {
      lines.push("");
      for (const warn of result.warnings) {
        lines.push(`  WARN: ${relativePath(warn.path)} — ${warn.warning}`);
      }
    }

    if (result.excluded.length > 0 && result.excluded.length <= 20) {
      lines.push("");
      for (const ex of result.excluded) {
        lines.push(`  SKIP: ${relativePath(ex.path)} — ${ex.reason}`);
      }
    } else if (result.excluded.length > 20) {
      lines.push(
        `\n  (${result.excluded.length} excluded files — use --json for full list)`
      );
    }
  }

  if (s.standard_object_fields.length > 0) {
    lines.push("");
    lines.push(
      `Standard object fields: ${s.standard_object_fields.join(", ")}`
    );
    lines.push(
      "  Note: These require explicit package.xml entries (wildcard won't capture them)"
    );
  }

  return lines.join("\n");
}

// ---------------------------------------------------------------------------
// Programmatic API — require() from other scripts/skills
// ---------------------------------------------------------------------------

/**
 * Validate a list of absolute file paths.
 * @param {string[]} files - Absolute paths to validate
 * @returns {object} Validation result object
 */
function validateFiles(files) {
  return validate(files);
}

/**
 * Validate all files under the metadata path.
 * @returns {object} Validation result object
 */
function validateAll() {
  const files = collectFilesRecursive(FORCE_APP);
  return validate(files);
}

/**
 * Validate files from a git diff.
 * @param {string} [ref] - Git ref to diff against (default: HEAD)
 * @returns {object} Validation result object
 */
function validateGitDiff(ref) {
  const files = getFilesFromGitDiff(ref);
  return validate(files);
}

module.exports = { validateFiles, validateAll, validateGitDiff };

// ---------------------------------------------------------------------------
// CLI entry point
// ---------------------------------------------------------------------------

if (require.main === module) {
  const files = resolveFiles(CLI_OPTS);
  const result = validate(files);

  if (CLI_OPTS.json) {
    const normalize = (obj) => {
      if (obj && typeof obj.path === "string") {
        obj.path = relativePath(obj.path);
      }
      return obj;
    };
    const output = {
      deployable: result.deployable.map(normalize),
      excluded: result.excluded.map(normalize),
      errors: result.errors.map(normalize),
      warnings: result.warnings.map(normalize),
      summary: result.summary
    };
    output.summary.standard_object_fields =
      result.summary.standard_object_fields;
    console.log(JSON.stringify(output, null, 2));
  } else {
    console.log(formatHuman(result, CLI_OPTS.summary));
  }

  if (result.errors.length > 0) {
    process.exit(1);
  }
}
